"""
Top 100 coding interview problems (Blind 75 + NeetCode-style).
Import get_additional_problems() and extend seed_db problems list.
Each problem uses LeetCode-style starter + driver from seed_starters.
"""
from models import TestCase, Difficulty
from seed_starters import get_starters_for_problem


def _problem(title, description, difficulty, tags, companies, test_cases, solution=None, hints=None):
    starters = get_starters_for_problem(title)
    return {
        "title": title,
        "description": description,
        "difficulty": difficulty,
        "tags": tags,
        "companies": companies,
        "test_cases": test_cases,
        "starter_code_python": starters["starter_code_python"],
        "driver_code_python": starters["driver_code_python"],
        "starter_code_javascript": starters["starter_code_javascript"],
        "driver_code_javascript": starters["driver_code_javascript"],
        "solution": solution if solution is not None else "",
        "hints": list(hints) if hints is not None else [],
    }


